  } catch (err) {
    if (err instanceof Error && (err.name === 'NotFound' || err.message.includes('Not Found'))) {
      return NextResponse.json({ error: 'Transaction not found' }, { status: 404 })
    }
    throw err
  }

  if (!transaction) {
